def transition(state, action):
    s = dict(state)
    judges = {k: dict(v) for k, v in s["judges"].items()}
    cases = {k: dict(v) for k, v in s["cases"].items()}
    s["judges"] = judges
    s["cases"] = cases

    name = action.get("name")
    params = action.get("params") or {}

    def least_loaded_judge():
        free = sorted((v["load"], k) for k, v in judges.items()
                      if v["load"] < v["capacity"])
        return free[0][1] if free else None

    if name == "assign":
        case = params.get("case")
        if case is None:
            waiting = sorted(k for k, c in cases.items() if c["judge"] is None
                             and c["status"] == "filed")
            case = waiting[0] if waiting else None
        judge = params.get("judge")
        if judge is None and case is not None:
            judge = least_loaded_judge()
        if (case in cases and judge in judges
                and cases[case]["judge"] is None
                and cases[case]["status"] == "filed"
                and judges[judge]["load"] < judges[judge]["capacity"]):
            cases[case]["judge"] = judge
            cases[case]["status"] = "assigned"
            judges[judge]["load"] += 1

    elif name == "reschedule":
        case = params.get("case")
        if case is None:
            pending = sorted(k for k, c in cases.items()
                             if c["status"] in ("assigned", "scheduled"))
            case = pending[0] if pending else None
        if case in cases and cases[case]["status"] in ("assigned", "scheduled"):
            day = params.get("day")
            if day is None:
                day = (cases[case]["day"] or s["day"]) + 1
            cases[case]["day"] = int(day)
            cases[case]["status"] = "scheduled"

    elif name == "hear":
        case = params.get("case")
        if case is None:
            ready = sorted(k for k, c in cases.items()
                           if c["status"] == "scheduled" and c["judge"] is not None)
            case = ready[0] if ready else None
        if (case in cases and cases[case]["status"] == "scheduled"
                and cases[case]["judge"] is not None):
            judge = cases[case]["judge"]
            cases[case]["status"] = "heard"
            s["heard"] = s["heard"] + 1
            if judges[judge]["load"] > 0:
                judges[judge]["load"] -= 1
            s["day"] = max(s["day"], int(cases[case]["day"]))

    return s

