def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' in line:
            k, v = line.split(':', 1)
            k = k.strip().lower(); v = v.strip()
            if k == 'day' and v.lstrip('-').isdigit():
                out['day'] = int(v)
    return out
